const grade11Final = [
  { id:'g11_rf1', grade:10, topic:'recursivitate', difficulty:3, type:'output_predict', question:'Ce afișează numărul de cai intr-o grila 3x3 (dreapta/jos)?', code:'def cai(m, n):\n    if m == 1 or n == 1: return 1\n    return cai(m-1, n) + cai(m, n-1)\nprint(cai(3, 3))', options:['6','4','8','9'], answer:'6', explanation:'Grila 3x3: cai(3,3)=cai(2,3)+cai(3,2)=3+3=6. Echivalent cu C(4,2)=6.', hint:'cai(3,3) = cai(2,3) + cai(3,2) = 3 + 3 = 6.' },
  { id:'g11_rf2', grade:10, topic:'recursivitate', difficulty:2, type:'output_predict', question:'Ce afișează maximul recursiv dintr-o lista?', code:'def maxim(lst):\n    if len(lst) == 1: return lst[0]\n    rest_max = maxim(lst[1:])\n    return lst[0] if lst[0] > rest_max else rest_max\nprint(maxim([3, 7, 2, 9, 5]))', options:['9','7','5','3'], answer:'9', explanation:'Compara recursiv capul listei cu maximul cozii. maxim([3,7,2,9,5]) = 9.', hint:'maxim(lst) = max(lst[0], maxim(lst[1:])).' },
  { id:'g11_rf3', grade:10, topic:'recursivitate', difficulty:3, type:'output_predict', question:'Ce afișează suma recursivă a elementelor pare?', code:'def suma_pare(v, i=0):\n    if i == len(v): return 0\n    return (v[i] if v[i]%2==0 else 0) + suma_pare(v, i+1)\nprint(suma_pare([1, 2, 3, 4, 5, 6]))', options:['12','6','9','21'], answer:'12', explanation:'Elementele pare: 2,4,6. Suma: 2+4+6=12.', hint:'La fiecare pas, adaugam v[i] dacă e par, altfel 0.' },
  { id:'g11_rf4', grade:10, topic:'recursivitate', difficulty:2, type:'output_predict', question:'Ce afișează inversarea recursivă a unui vector?', code:'def invers(v):\n    if len(v) <= 1: return v\n    return invers(v[1:]) + [v[0]]\nprint(invers([1, 2, 3, 4]))', options:['[4, 3, 2, 1]','[1, 2, 3, 4]','[4, 1]','Eroare'], answer:'[4, 3, 2, 1]', explanation:'invers([1,2,3,4]) = invers([2,3,4]) + [1] = [4,3,2] + [1] = [4,3,2,1].', hint:'La fiecare apel, primul element merge la sfârșit.' },
  { id:'g11_rf5', grade:10, topic:'recursivitate', difficulty:3, type:'multiple_choice', question:'Ce optimizare transforma Fibonacci din O(2^n) la O(n)?', code:'', options:['Memoizare (cacheing subproblemelor)','Cresterea limitei recursivitații','Conversia la for','Utilizarea float'], answer:'Memoizare (cacheing subproblemelor)', explanation:'Fib naiv recalculeaza aceleasi valori de mii de ori. Memoizarea stocheaza rezultatele = O(n).', hint:'Memo = cache. fib(30) fara memo: ~1M apeluri. Cu memo: 30 apeluri.' },
  { id:'g11_bf1', grade:11, topic:'backtracking', difficulty:3, type:'output_predict', question:'Câte permutari afișează codul pentru [1,2,3]?', code:'def perm(arr, k=0):\n    if k == len(arr):\n        print(arr[:])\n    for i in range(k, len(arr)):\n        arr[k], arr[i] = arr[i], arr[k]\n        perm(arr, k+1)\n        arr[k], arr[i] = arr[i], arr[k]\nperm([1,2,3])', options:['6','3','9','24'], answer:'6', explanation:'3! = 3x2x1 = 6 permutari ale lui [1,2,3].', hint:'P(3) = 3! = 6 permutari.' },
  { id:'g11_bf2', grade:11, topic:'backtracking', difficulty:3, type:'multiple_choice', question:'Cum obtii "prima soluție" versus "toate solutiile" in backtracking?', code:'', options:['Prima: return dupa prima soluție gasita; Toate: continuam explorarea','Nu există diferenta','Prima soluție e mereu cea mai buna','Sunt identice'], answer:'Prima: return dupa prima solutie gasita; Toate: continuam explorarea', explanation:'Prima soluție: return/break dupa prima gasita. Toate solutiile: continuam explorarea dupa fiecare soluție.', hint:'break/return dupa prima vs. continuare dupa fiecare soluție.' },
  { id:'g11_bf3', grade:11, topic:'backtracking', difficulty:2, type:'output_predict', question:'Câte submultimi de suma 5 are multimea {1, 2, 3, 4, 5}?', code:'# Cauta: {1,4}=5, {2,3}=5, {5}=5', options:['3','2','4','5'], answer:'3', explanation:'Submultimile cu suma 5: {1,4}=5, {2,3}=5, {5}=5. Total: 3.', hint:'Cauta: {5}, {1,4}, {2,3}.' },
  { id:'g11_sdf1', grade:9, topic:'stive_cozi', difficulty:2, type:'multiple_choice', question:'Ce operatie e mai eficienta pe deque față de o lista pentru inserare la început?', code:'', options:['O(1) pe deque vs O(n) pe lista','O(1) pe ambele','O(n) pe ambele','O(n) pe deque'], answer:'O(1) pe deque vs O(n) pe lista', explanation:'deque.appendleft() = O(1). list.insert(0, x) = O(n) (deplaseaza toate elementele).', hint:'deque = double-ended queue. Inserare la capete = O(1).' },
  { id:'g11_sdf2', grade:9, topic:'stive_cozi', difficulty:2, type:'multiple_choice', question:'Care structura de date implementeaza politica FIFO?', code:'', options:['Coada (Queue)','Stiva (Stack)','Heap','Arbore binar'], answer:'Coada (Queue)', explanation:'FIFO = First In First Out = coada. Stiva = LIFO.', hint:'FIFO = coada. LIFO = stiva.' },
  { id:'g11_sdf3', grade:11, topic:'grafuri', difficulty:3, type:'output_predict', question:'Ce afișează BFS simulat cu coada (ordinea vizitării)?', code:'from collections import deque\ngraf = {1:[2,3], 2:[4], 3:[5], 4:[], 5:[]}\nq = deque([1])\nviz = []\nwhile q:\n    n = q.popleft()\n    if n not in viz:\n        viz.append(n)\n        q.extend(graf[n])\nprint(viz)', options:['[1, 2, 3, 4, 5]','[1, 3, 5, 2, 4]','[5, 4, 3, 2, 1]','Eroare'], answer:'[1, 2, 3, 4, 5]', explanation:'BFS cu coada: vizitează 1, adaugă 2,3; vizitează 2, adaugă 4; vizitează 3, adaugă 5; 4; 5.', hint:'BFS = coada = vizitează nodul, adaugă vecinii nevizitati.' },
  { id:'g11_sdf4', grade:9, topic:'stive_cozi', difficulty:3, type:'output_predict', question:'Ce afișează verificarea echilibrului parantezelor "({[]})"?', code:'expr = "({[]})"\nst = []\npeche = {")":"(", "}":"{", "]":"["}\nok = True\nfor c in expr:\n    if c in "({[": st.append(c)\n    elif c in ")}]":\n        if not st or st[-1] != peche[c]: ok=False; break\n        else: st.pop()\nprint(ok and not st)', options:['True','False','None','Eroare'], answer:'True', explanation:'"({[]})" e echilibrata: fiecare paranteza inchisa corespunde ultimei deschise. Stiva goala la final.', hint:'La fiecare paranteza inchisa: trebuie sa corespunda cu varful stivei.' },
  { id:'g11_oof1', grade:11, topic:'OOP', difficulty:3, type:'output_predict', question:'Ce afișează @property cu setter (validare raza)?', code:'class Cerc:\n    def __init__(self, r):\n        self._r = r\n    @property\n    def raza(self): return self._r\n    @raza.setter\n    def raza(self, val):\n        if val > 0: self._r = val\n\nc = Cerc(5)\nc.raza = 10\nprint(c.raza)\nc.raza = -1\nprint(c.raza)', options:['10\n10','5\n5','10\n-1','Eroare'], answer:'10\n10', explanation:'setter valideaza: 10>0 = _r=10. -1<0 = nu se schimba. A doua print: tot 10.', hint:'@property cu setter permite validare la atribuire.' },
  { id:'g11_oof2', grade:11, topic:'OOP', difficulty:2, type:'multiple_choice', question:'Ce face super().__init__() intr-un constructor Python?', code:'', options:['Apelează constructorul clasei de baza','Creeaza o noua instanta','Returnează clasa de baza','Sterge atributele mostenite'], answer:'Apeleaza constructorul clasei de baza', explanation:'super().__init__(...) apelează constructorul clasei parinte, initializand atributele mostenite.', hint:'super() = acces la clasa parinte.' },
  { id:'g11_oof3', grade:11, topic:'OOP', difficulty:3, type:'output_predict', question:'Ce afișează polimorfismul cu o lista de animale?', code:'class Animal:\n    def sunet(self): return "..."\nclass Caine(Animal):\n    def sunet(self): return "Ham"\nclass Pisica(Animal):\n    def sunet(self): return "Miau"\n\nanimale = [Caine(), Pisica(), Caine()]\nprint([a.sunet() for a in animale])', options:["['Ham', 'Miau', 'Ham']","['...', '...', '...']","['Caine', 'Pisica', 'Caine']","Eroare"], answer:"['Ham', 'Miau', 'Ham']", explanation:'Polimorfism: fiecare obiect apelează propria metoda sunet(). Caine=Ham, Pisica=Miau.', hint:'Polimorfism: acelasi apel, comportamente diferite in funcție de tip.' },
  { id:'g11_oof4', grade:11, topic:'OOP', difficulty:2, type:'output_predict', question:'Ce afișează __init__ mostenit cu super()?', code:'class Animal:\n    def __init__(self, nume): self.nume = nume\n\nclass Pisica(Animal):\n    def __init__(self, nume, culoare):\n        super().__init__(nume)\n        self.culoare = culoare\n\np = Pisica("Miau", "portocaliu")\nprint(p.nume, p.culoare)', options:['Miau portocaliu','Miau','portocaliu','Eroare'], answer:'Miau portocaliu', explanation:'super().__init__(nume) apelează Animal.__init__ care setează self.nume. Pisica setează self.culoare.', hint:'super().__init__ = apel constructor parinte. Pisica setează ambele atribute.' },
  { id:'g11_oof5', grade:11, topic:'OOP', difficulty:3, type:'multiple_choice', question:'Care principiu OOP descrie tratarea unui obiect ca instanta a clasei de baza?', code:'', options:['Polimorfismul','Encapsularea','Abstractizarea','Supraincarcarea'], answer:'Polimorfismul', explanation:'Polimorfismul: un Caine poate fi tratat ca Animal. Acelasi apel sunet() produce rezultate diferite.', hint:'Poli = multi. Acelasi apel, comportamente diferite.' },
  { id:'g11_wf1', grade:11, topic:'scriere_11', difficulty:3, type:'write', question:'Scrie linia return din __add__ care returnează suma a doua obiecte Punct.', code:'class Punct:\n    def __init__(self, x, y): self.x=x; self.y=y\n    def __add__(self, other):\n        return ___', answer:'Punct(self.x + other.x, self.y + other.y)', altAnswers:['Punct(self.x+other.x, self.y+other.y)'], explanation:'__add__ trebuie sa returneze un nou obiect Punct cu coordonatele sumate.', hint:'return Punct(suma x-urilor, suma y-urilor).' },
  { id:'g11_wf2', grade:10, topic:'scriere_10', difficulty:3, type:'write', question:'Completeaza funcția recursivă care calculează suma elementelor unui vector.', code:'def suma_v(v):\n    if not v: return 0\n    return ___', answer:'v[0] + suma_v(v[1:])', altAnswers:['v[0]+suma_v(v[1:])'], explanation:'Cazul recursiv: primul element + suma recursivă a restului listei.', hint:'suma_v(v) = v[0] + suma_v(restul).' },
  { id:'g11_wf3', grade:11, topic:'scriere_11', difficulty:2, type:'write', question:'Scrie linia care apelează constructorul clasei de baza Animal din Caine.', code:'class Caine(Animal):\n    def __init__(self, nume, rasa):\n        ___\n        self.rasa = rasa', answer:'super().__init__(nume)', altAnswers:['Animal.__init__(self, nume)'], explanation:'super().__init__(argumente) apelează constructorul clasei parinte.', hint:'super().__init__(...) = apel constructor parinte.' },
  { id:'g11_wf4', grade:11, topic:'scriere_11', difficulty:3, type:'write', question:'Scrie condiția de pruning: oprește dacă suma partiala depaseste target-ul.', code:'def bt(v, i, sol, target):\n    if sum(sol) == target: print(sol[:]); return\n    if ___: return\n    for j in range(i, len(v)):\n        sol.append(v[j])\n        bt(v, j+1, sol, target)\n        sol.pop()', answer:'sum(sol) > target', altAnswers:['sum(sol)>target'], explanation:'Dacă suma partiala depaseste target-ul, nicio extensie nu poate fi valida (valori pozitive).', hint:'Condiția de pruning: suma curenta > target.' },
  { id:'g11_wf5', grade:11, topic:'scriere_11', difficulty:2, type:'write', question:'Scrie linia care marchează elementul v[i] ca folosit in algoritmul de permutari.', code:'def perm(v, k, sol, used):\n    if k == len(v): print(sol); return\n    for i in range(len(v)):\n        if not used[i]:\n            sol.append(v[i])\n            ___\n            perm(v, k+1, sol, used)\n            sol.pop()\n            used[i] = False', answer:'used[i] = True', altAnswers:['used[i]=True'], explanation:'Marcam elementul ca folosit INAINTE de apelul recursiv, pentru a evita reutilizarea.', hint:'Marchează INAINTE de recursie. Demarchează DUPA.' },
  { id:'g11_wf6', grade:11, topic:'scriere_11', difficulty:3, type:'write', question:'Scrie metoda __str__ care returnează "Cerc(raza=5)" pentru raza=5.', code:'class Cerc:\n    def __init__(self, raza): self.raza = raza\n    def __str__(self):\n        return ___', answer:'f"Cerc(raza={self.raza})"', altAnswers:['f\'Cerc(raza={self.raza})\''], explanation:'f-string: f"Cerc(raza={self.raza})" produce "Cerc(raza=5)" pentru self.raza=5.', hint:'Folosește f-string: f"Cerc(raza={self.raza})".' },
];

